"""MetricsAggregator for async training.

Accumulates metric observations from multiple sources (buffer, training loop,
coordinator) and reduces them with per-key aggregation rules at flush time.
"""

from __future__ import annotations

from collections import defaultdict

import numpy as np

# Keys that should be summed rather than averaged.
_SUM_KEYS: set[str] = {
    "groups/num_trajs_before_filter",
    "groups/num_trajs_after_filter",
    "groups/num_groups",
    "groups/dropped_min_trajs",
    "groups/dropped_zero_adv",
}

# Prefixes where "last value" is the correct reduction.
_LAST_PREFIXES: tuple[str, ...] = (
    "time/",
    "train/",
    "progress/",
    "async/",
)

# Prefixes where "mean" is the correct reduction.
_MEAN_PREFIXES: tuple[str, ...] = ("episode/",)


def _infer_rule(key: str) -> str:
    """Infer aggregation rule from metric key name.

    Resolution order:
    1. Explicit sum keys
    2. Prefix-based rules (last or mean)
    3. Keyword-based rules (/max, /min, /mean, /avg, /std, /fraction)
    4. Default: mean
    """
    if key in _SUM_KEYS:
        return "sum"

    for prefix in _LAST_PREFIXES:
        if key.startswith(prefix):
            return "last"

    for prefix in _MEAN_PREFIXES:
        if key.startswith(prefix):
            return "mean"

    # Keyword inference from the key name
    if "/max" in key:
        return "max"
    if "/min" in key:
        return "min"
    if "/mean" in key or "/avg" in key:
        return "mean"
    if "/std" in key or "/fraction" in key:
        return "mean"

    return "mean"


def _reduce(rule: str, values: list[float]) -> float:
    if rule == "mean":
        return sum(values) / len(values)
    if rule == "sum":
        return sum(values)
    if rule == "max":
        return max(values)
    if rule == "min":
        return min(values)
    if rule == "last":
        return values[-1]
    return sum(values) / len(values)


class MetricsAggregator:
    """Accumulates metric observations and flushes as an aggregated plain dict.

    Usage::

        agg = MetricsAggregator()

        # record from various sources
        agg.record("episode/queue_wait", 0.3)
        agg.record("episode/queue_wait", 0.5)
        agg.record_dict(transform_metrics)

        # at log time
        plain_dict = agg.flush()  # reduces, clears, returns dict
    """

    def __init__(self) -> None:
        self._values: dict[str, list[float]] = defaultdict(list)

    def record(self, key: str, value: float) -> None:
        """Record a single metric observation."""
        self._values[key].append(float(value))

    def record_dict(self, metrics: dict) -> None:
        """Record all numeric values from a dict, coercing types."""
        for k, v in metrics.items():
            if isinstance(v, int | float):
                self._values[k].append(float(v))
            elif isinstance(v, np.number):
                self._values[k].append(float(v))

    def flush(self) -> dict[str, float]:
        """Reduce all accumulated values and return a plain dict. Clears state."""
        result = {}
        for key, values in self._values.items():
            if values:
                result[key] = _reduce(_infer_rule(key), values)
        self._values.clear()
        return result

"""Compatibility helpers around Verl's debug metric utilities."""

from __future__ import annotations

import logging
import math
from collections.abc import Callable
from typing import Any

logger = logging.getLogger(__name__)
_EMPTY_REDUCTION_ERROR_SNIPPETS = (
    "Expected reduction dim to be specified",
    "input.numel() == 0",
)


def _load_verl_calculate_debug_metrics() -> Callable[[Any], dict[str, float]]:
    """Load Verl's debug metrics helper lazily to preserve optional dependency boundaries."""
    from verl.utils.debug.metrics import calculate_debug_metrics

    return calculate_debug_metrics


def _default_debug_metrics() -> dict[str, float]:
    """Mirror the newer upstream fallback for all-zero valid-token masks."""
    return {
        "training/rollout_probs_diff_valid": 0,
        "training/rollout_probs_diff_max": float("nan"),
        "training/rollout_probs_diff_mean": float("nan"),
        "training/rollout_probs_diff_std": float("nan"),
        "training/rollout_actor_probs_pearson_corr": float("nan"),
    }


def _is_legacy_empty_mask_error(exc: RuntimeError) -> bool:
    """Detect the empty-mask reduction failure from older Verl helper versions."""
    message = str(exc)
    return all(snippet in message for snippet in _EMPTY_REDUCTION_ERROR_SNIPPETS)


def _normalize_degenerate_std(metrics: dict[str, float]) -> dict[str, float]:
    """Clamp the single-token std case to zero without masking broader metric failures."""
    std = metrics.get("training/rollout_probs_diff_std", float("nan"))
    if metrics.get("training/rollout_probs_diff_valid") != 1 or not math.isnan(std):
        return metrics

    if math.isnan(metrics.get("training/rollout_probs_diff_max", float("nan"))):
        return metrics
    if math.isnan(metrics.get("training/rollout_probs_diff_mean", float("nan"))):
        return metrics

    metrics["training/rollout_probs_diff_std"] = 0.0
    return metrics


def calculate_debug_metrics_compat(data: Any) -> dict[str, float]:
    """Delegate to Verl's helper while backfilling legacy empty-mask behavior."""
    try:
        metrics = _load_verl_calculate_debug_metrics()(data)
    except RuntimeError as exc:
        if not _is_legacy_empty_mask_error(exc):
            raise
        logger.warning("Verl debug metrics hit an empty valid-token mask, returning default metrics")
        return _default_debug_metrics()

    return _normalize_degenerate_std(metrics)

